Java Solution:

	public static void main(String[] args) {
		int[] nums = {2, 1, 3, 0, 3};
		int target = 5;
		List<int[]> res = new ArrayList<>();
		find3SumGreater(res, nums, target);
		for(int[] ele : res)
			System.out.println(Arrays.toString(ele));
	}

	private static void find3SumGreater(List<int[]> res, int[] nums, int target) {
		Arrays.sort(nums);
		for(int i=0;i<nums.length-2;i++) {
			int l = i+1, r = nums.length-1;
			int tmp = target - nums[i];
			while(l < r) {
				if(nums[l] + nums[r] <= tmp)
					l++;
				else {
					for(int j=l;j<r && r>l; j++) {
						res.add(new int[] {nums[i], nums[j], nums[r]});
					}
					r--;
				}
			}
		}
	}

