JS solution

```
const threeSumGreater = (nums, target) => {
  let triplets = 0

  if(nums && nums.length >= 3) {
    nums.sort()

    for(let i = 0; i < nums.length-2; i++) {
      let j = i + 1
      let k = nums.length - 1

      while (j < k) {
        if(nums[i] + nums[j] + nums [k] > target) {
          triplets += k - j
          k--
        } else {
          j++
        }
      }
    }
  }

  return triplets
}

